# ``_record_task_failure`` is classified into one stable class and written as a
# ``heiler_classification`` task_event (payload = class + evidence). The read
# side ``read_escalation_ledger`` aggregates them; the Stratege (Phase 1.5)
# derives root-cause Specs from that rollup. This phase does NOT spawn a fix
# worker and does NOT change escalation-after-N — that keeps using the existing
# ``operator_escalation`` event next to the classification.
HEILER_CLASSIFICATION_EVENT = "heiler_classification"
# Operator override of an auto classification (HEILER-CLASSIFY-COVERAGE-S1).
# Stored as its own event so the auto ``heiler_classification`` ledger
# (``by_class``, the Stratege's input) stays the record of what the *pipeline*
# decided, while the coverage metric can measure how often a human had to step
# in (the AC-2 misclassification guardrail).
HEILER_CLASSIFICATION_CORRECTED_EVENT = "heiler_classification_corrected"
# Source tags on a ``heiler_classification`` payload: who emitted it. Inline
# sites use their function name ("record_task_failure" / "stall_park"); the
# safety-net sweep tags itself so the ledger shows backfilled vs atomic.
HEILER_SOURCE_ESCALATION_SWEEP = "escalation_sweep"
# Inline source tags for the two escalation write paths that historically left
# classification to the safety-net sweep (ESCALATION-INLINE-CLASSIFY-S1). They
# now classify atomically at the write site (defense-in-depth, not a duplicate
# of the sweep), so the Stratege gets immediately-complete cause evidence
# instead of a poll-dependent approximation. The release-gate writer lives in
# ``kanban_worktrees`` but tags itself here so all source vocabulary is colocated.
HEILER_SOURCE_BUDGET_RUNAWAY = "budget_runaway_park"
HEILER_SOURCE_RELEASE_GATE = "release_gate_escalation"
HEILER_SOURCE_NONSPAWNABLE = "nonspawnable_assignee_escalation"
# The silent-block sweep is itself an escalation writer (it surfaces settled
# blocks that never escalated on their own path). ESCALATION-INLINE-CLASSIFY-S1
# closes it as the last escalation write path without inline classification: it
# now pairs a heiler_classification atomically in the same write_txn, tagged
# with this source so the ledger distinguishes it from the backfill sweep.
HEILER_SOURCE_SILENT_BLOCK = "silent_block_escalation"
# Source tag on an ``operator_escalation`` payload emitted by the silent-block
# safety-net sweep (SILENT-BLOCK-GUARD-S1): a block the self-healing retry lane
# is done with but that never raised an escalation on its own block path.
SILENT_BLOCK_ESCALATION_SOURCE = "silent_block_sweep"
# Autonomy routing (SILENT-BLOCK-AUTONOMY-S1): when a block is settled for the
# auto-retry lane, prefer a *bounded* machine next-step over paging the operator.
# Token discipline: at most one re-ready per block episode; hold-classes do not
# re-dispatch workers (zero token burn) and only observe/classify.
AUTONOMY_ROUTED_EVENT = "autonomy_routed"
# Token bound: at most one re-ready per block *episode* AND at most one
# re-ready over the whole task lifetime. Episode-only caps re-arm on every
# re-block and would allow review thrash forever (Opus 4.8 review blocker).
MAX_AUTONOMY_REREADY_PER_EPISODE = 1
MAX_AUTONOMY_REREADY_PER_TASK = 1
# Routes that re-dispatch a worker (token cost). Holds do not.
# Only review rework is re-dispatched; generic exhausted/stuck blocks still
